203â†’	}
204â†’
205â†’	q := fmt.Sprintf(
206â†’		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
207â†’		distanceExpr, myPriceExpr, blendExpr,
208â†’	)
209â†’	if len(clauses) > 0 {
210â†’		q += " WHERE " + strings.Join(clauses, " AND ")
211â†’	}
212â†’
213â†’	if req.Blend != nil && req.Sort == nil {
214â†’		q += " ORDER BY 10 ASC NULLS LAST"
215â†’	} else {
216â†’		orderBy, err := buildOrderBy(reg, req)
217â†’		if err != nil {
218â†’			return "", nil, err
219â†’		}
220â†’		q += orderBy
221â†’	}
222â†’
223â†’	limit := req.Limit
224â†’	if limit <= 0 {
