236â†’// permanentFilter is an unconditional WHERE clause applied to every query.
237â†’// It excludes non-degree-granting locations (0), certificate-only programs (1),
238â†’// and associate's-only institutions (2), keeping only Bachelor's or higher (â‰Ą 3).
239â†’const permanentFilter = "COALESCE((data #>> '{nces,degrees_awarded_highest}')::int, 0) >= 3"
240â†’
241â†’// buildWhere resolves each FilterInput to a SQL clause, advancing the placeholder
242â†’// index across filters so that $N numbering is globally consistent within one query.
243â†’func buildWhere(reg *Registry, filters []FilterInput) (clauses []string, args []any, err error) {
244â†’	clauses = []string{permanentFilter}
245â†’	argStart := 1
246â†’	for _, fi := range filters {
247â†’		field, ok := reg.Lookup(fi.Field)
248â†’		if !ok {
249â†’			return nil, nil, fmt.Errorf("unknown field %q", fi.Field)
250â†’		}
251â†’		clause, fieldArgs, ferr := field.BuildSQL(fi.Value, argStart)
252â†’		if ferr != nil {
253â†’			return nil, nil, fmt.Errorf("field %q: %w", fi.Field, ferr)
254â†’		}
255â†’		clauses = append(clauses, clause)
256â†’		args = append(args, fieldArgs...)
257â†’		argStart += len(fieldArgs)
258â†’	}
259â†’	return clauses, args, nil
260â†’}
